VALUES
  ('social-worker-moex-05530', 'social-worker', 'social-worker-moex-106-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列何種做法未違反研究倫理？', '["實驗者在受試者不知情狀況下利用單面鏡觀察受試者行為", "某研究幫派的研究者拒絕將幫派名單給警察單位", "為了讓研究能觀察出受試者的真正行為表現，研究者隱瞞自己研究者身分", "為了招募更多的實驗參與者，研究主持人事先告知參與實驗者會有好處"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "8a86e172f0f5", "answer_pdf_sha1": "58115afe2e3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05531', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'essay', '請說明績效管理的要素（15分）及績效管理對社會工作的意義。（10分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "15e37dd6688d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": "一", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05532', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'essay', '近年社會福利機構大量運用行銷手法以增加機構的能見度、募款等，然而社會福利
機構的性質畢竟與營利機構不同，請說明社會福利機構運用的行銷與商業組織進行
的行銷間的差異（15分）及成功募款所需具備的基本原則。（10分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "15e37dd6688d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05533', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '小王是某一社會福利機構的主管，他為了希望為機構的未來運作與發展提供一個明確方向，以降低整體 社會福利發展環境的不確定因素及變遷對機構帶來的衝擊，並減少資源的浪費，增加成功的機會，因此 他針對機構未來的發展目標、策略及行動予以盤算、分析與選取，小王這個行為是他發揮下列那一個管 理職能？', '["領導", "決策", "組織", "規劃"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "15e37dd6688d", "answer_pdf_sha1": "e38b093537b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05534', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '組織的設計傾向於扁平式、決策分權化及水平的溝通，組織的分工較為模糊，賦予員工較多的自由，期 待以彈性取代標準化作業，並透過資訊的分享與相互協調的溝通與合作方式，以促進組織功能間的整合， 此種設計的組織結構稱為：', '["機械型結構", "無機型結構", "有機型結構", "電腦型結構"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "15e37dd6688d", "answer_pdf_sha1": "e38b093537b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05535', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '如果一個社會福利服務機構，主要希望機構可提供能回應地方需求的服務，並考慮積極經營地方關係， 增進服務的可近性，則其組織的部門劃分最好採取下列那一種類型？', '["依「案主」分部化", "依「地區」分部化", "依「服務」分部化", "依「功能」分部化"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "15e37dd6688d", "answer_pdf_sha1": "e38b093537b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05536', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '某一有名的老人安養機構在當地已20年了，這段期間在照顧住民且滿足他們的需求以及回應家庭的請求 上，已建立良好的名聲。該機構最近換了一位新主管，他認為機構目前的工作氣氛過於輕鬆，因此決定 對員工進行一些嚴格控管的措施，包括員工每天要完成自己的工作檢視表，同時明確地規定他們每天要 做的事及每天工作中每小時要去的地點。請問這位新主管所採取的管理哲學為：', '["Y理論", "X理論", "Z理論", "G理論"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "15e37dd6688d", "answer_pdf_sha1": "e38b093537b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05537', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '組織決策集中化和分散化各有優缺點，下列那一個敘述是指組織決策集中化的優點？', '["可以減低高階管理者的負擔", "促進決策的速度", "讓決策更接近工作的作業層級", "更趨於扁平化和彈性結構的發展"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "15e37dd6688d", "answer_pdf_sha1": "e38b093537b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05538', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '「在10週的團體活動方案結束後，參與的8位長輩的情緒憂鬱狀況獲得改善，其憂鬱量表的得分，至少 70%的長輩在得分方面有改善。」上述的陳述表達方案計畫中的什麼概念？', '["目的", "活動目標", "成果目標", "過程目標"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "15e37dd6688d", "answer_pdf_sha1": "e38b093537b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05539', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在方案計畫中呈現方案進行方式的程序圖，它運用文字或圖片來描述活動的序列和方案活動帶來的變 化，並將這些活動與方案的「成果目標」或「服務績效」做連結。它是一個系統性的模型，透過這個模 型可以使他人了解「方案運用的資源」、「方案運作的程序與計畫的活動」、「方案預期的產出或輸出」 與「預期達到的目標或服務績效」等四者之間的關係，是中華社會福利聯合勸募協會在大力推行的一種 方案撰寫的架構模型，稱為：', '["知識模型", "理論模型", "邏輯模型", "認知模型"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "15e37dd6688d", "answer_pdf_sha1": "e38b093537b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
